#!/usr/bin/env bash
# sop.sh — 安全风控 SOP（行业生命线·最高优先级，贯穿全程） SOP walkthrough for 研学营地教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="研学营地教育"
WORKFLOW="安全风控 SOP（行业生命线·最高优先级，贯穿全程）"

usage() {
  cat <<EOF
sop.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./sop.sh             # interactive
  ./sop.sh --dry-run
  ./sop.sh --json
  ./sop.sh --explain
  ./sop.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "安全风控 SOP（行业生命线·最高优先级，贯穿全程）" 工作流。

一句话: 从「准备组织一次研学/营地活动」走到「三案齐备、三层险到位、人员配比达标、突发可处置、事后可复盘归档」的状态——这是研学营地行业的**第一性约束**：李璟晖「安全是1，后面的0才有意义」、王晓燕「活动有方案、行前有备案、应急有预案」，政策派与运营派罕见同频。任何其他 workflow 不过这一关都不准成行。

入门 SOP 共 7 步, 失败模式自检 3 项。

相关心智模型:
  • 「研学是课程不是行程」——教育属性优先: 研学/营地的本体是**课程**（有学习目标—实施—评价闭环），不是**行程**（景点+讲解词）；从业者用「教育本质」作为对抗旅游化、获客化、速成化的立场锚与对客叙事。
  • 体验—反思闭环（Kolb 圈）——「经验无反思即旅游」: 学习不是「去过/动手过」就发生，而要走完「具体经验→反思观察→抽象概念化→主动实践」的圈；**「反思/复盘」环节的有无，是研学区别于旅游的命门工序**。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**资质核验**：核承办方《旅行社业务经营许可证》+ 是否在研学服务机构名录 + 近三年无重大安全责任事故/质量投诉。跳过后果：用无资质或有黑历史机构，出事连带追责、被通报。 evidence: [W-S006, W-S007]"
  "**配比配置**：研学指导岗:参与者 **不低于 1:30**、随团服务人员:参与者 **不低于 1:20**（LB/T 054-2025）；地方更严的从地标（常德 1:15、营地按 ACA 年龄分级低龄 1:6）；**每团至少 1 名安全员全程随团**。跳过后果：配比超标是最常见违规，监管核查直接打回。 evidence: [W-S003, W-S006, W-S014]"
  "**风险评估+应急预案+演练**：针对极端天气/事故/疾病/治安做处置方案，按本线路/营地实地定制（一车一案/一队一案），并演练。跳过后果：**无预案不准成行**；照抄通用模板=形同虚设；不演练=临场乱套。 evidence: [W-S006, W-S010]"
  "**三层险栈**：主办学校投**校方责任险**、承办旅行社投**旅行社责任险**、师生投**人身意外伤害险**，三层叠加缺一不可（出境另加 24h 全球紧急救援险）。跳过后果：「只买一份意外险」是最常见致命错，赔付主体错位、保障缺口。 evidence: [W-S013, W-S005]"
  "**食宿/交通/医疗核查**：核查餐饮卫生、住宿安全（男女分室）、车辆/驾驶资质、就近医疗资源。跳过后果：食物中毒/交通/突发疾病无兜底。 evidence: [W-S008, W-S005]"
  "**行前安全教育+说明会**：对师生家长做安全交底（出行前一周）。跳过后果：学生无安全意识、家长信息不对称、突发联络断链。 evidence: [W-S006]"
  "**行中处置 + 行后复盘归档**：随团安全员防控、突发按预案处置；事后（含未遂）复盘并归档留存。跳过后果：同类风险反复、无改进证据、再出事追责加重。 evidence: [W-S003, W-S005]"
)
declare -a FAILURE_MODES=(
  "**三层险只买一层**：以为一份人身意外险就够，校方/旅行社责任险缺位，出事赔付主体与额度错位。→ 签约前逐层核对三层险投保主体+保额+起止时间（出境加全球救援）。 evidence: [W-S013]"
  "**应急预案照抄模板不演练**：拿通用模板交差备案，真出极端天气/交通事故时无人会用。→ 一车一案/一队一案+关键节点实地演练，安全员清单点验。 evidence: [W-S006, W-S010]"
  "**安全员兼岗形同虚设**：让导游/导师兼任安全员，忙起来安全无人专责。→ 每团配专职安全员全程随团，不与带教/行程岗兼任。 evidence: [W-S003]"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "sop-walkthrough"
fi
